import java.io.File;
import java.io.FileWriter;
import java.io.IOException;
import org.owasp.encoder.Encode;

public class XSSFixedCode {
    public static void main(String[] args) throws IOException {
        String userInput = "<script>alert('XSS Vulnerability')</script>";

        File file = new File("output.html");
        FileWriter writer = new FileWriter(file);
        writer.write("<html>");
        writer.write("<head><title>XSS Fixed Example</title></head>");
        writer.write("<body>");
        writer.write("<h1>User Input:</h1>");

        // Encode user input using OWASP Java Encoder
        String encodedInput = Encode.forHtml(userInput);
        writer.write(encodedInput); // User input is now properly encoded

        writer.write("</body>");
        writer.write("</html>");

        writer.close();
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
